#include <stdio.h>

unsigned int bit_and(unsigned int a, unsigned int b) {
    return a & b;
}

unsigned int bit_or(unsigned int a, unsigned int b) {
    return a | b;
}

unsigned int bit_xor(unsigned int a, unsigned int b) {
    return a ^ b;
}

unsigned int bit_not(unsigned int a) {
    return (~a) & 0xFF;
}

unsigned int bit_shift_left(unsigned int a, int n) {
    return (a << n) & 0xFF;
}

unsigned int bit_shift_right(unsigned int a, int n) {
    return a >> n;
}

int main(void) {
    {
        printf("%d\n", (int)(bit_and(0xA5, 0x0F)));
        printf("%d\n", (int)(bit_and(0xA5, 0x50)));
        printf("%d\n", (int)(bit_and(0xFF, 0xFF)));
        printf("%d\n", (int)(bit_and(0x00, 0xFF)));
    }
    {
        printf("%d\n", (int)(bit_or(0xA5, 0x0F)));
        printf("%d\n", (int)(bit_or(0xA5, 0x50)));
        printf("%d\n", (int)(bit_or(0xFF, 0x00)));
        printf("%d\n", (int)(bit_or(0x00, 0x0F)));
    }
    {
        printf("%d\n", (int)(bit_xor(0xA5, 0x0F)));
        printf("%d\n", (int)(bit_xor(0xA5, 0x50)));
        printf("%d\n", (int)(bit_xor(0xFF, 0x00)));
        printf("%d\n", (int)(bit_xor(0x00, 0xFF)));
    }
    {
        printf("%d\n", (int)(bit_not(0xA5)));
        printf("%d\n", (int)(bit_not(0xFF)));
        printf("%d\n", (int)(bit_not(0x00)));
        printf("%d\n", (int)(bit_not(0x50)));
    }
    {
        printf("%d\n", (int)(bit_shift_left(0xA5, 2)));
        printf("%d\n", (int)(bit_shift_left(0x50, 1)));
        printf("%d\n", (int)(bit_shift_left(0xFF, 1)));
        printf("%d\n", (int)(bit_shift_left(0x01, 2)));
    }
    {
        printf("%d\n", (int)(bit_shift_right(0xA5, 2)));
        printf("%d\n", (int)(bit_shift_right(0xA0, 2)));
        printf("%d\n", (int)(bit_shift_right(0xFF, 1)));
        printf("%d\n", (int)(bit_shift_right(0x01, 2)));
    }
    return 0;
}

